// n8n Code node — run mode: "Run Once for All Items"
// Builds an NCA Toolkit /v1/ffmpeg/compose payload: concatenates image_1..image_N
// and merges them with the voiceover. Each image is shown for an equal slice of the
// voiceover length -> perImage = voiceoverDuration / imageAmount.
// REQUIRES the voiceover duration (seconds) on the incoming item — feed an NCA
// /v1/media/metadata node on the voiceover.mp3 into this node first.

// ---- output video settings ----
const WIDTH  = 1920;
const HEIGHT = 1080;
const FPS    = 30;
const WEBHOOK_URL = ''; // optional: webhook URL for async (long) jobs

// find the voiceover duration (seconds) from whatever the metadata node returned
function findDuration(j) {
  const candidates = [
    j['Voiceover Duration'], j['voiceover_duration'], j['duration'],
    j.metadata && j.metadata.duration,
    j.format && j.format.duration,
    j.response && j.response.duration,
  ];
  for (const c of candidates) {
    const n = parseFloat(c);
    if (!isNaN(n) && n > 0) return n;
  }
  return null;
}

return $input.all().map((entry, idx) => {
  const j = entry.json;

  const voiceover = j['Voiceover Path'];
  const imageBase = j['Image Path'];   // e.g. ".../images/image_"
  const amount    = parseInt(j['Image Amount'], 10);
  const ext       = j['Image Type'];   // e.g. ".jpg" (includes the dot)

  const duration = findDuration(j);
  if (!duration) {
    throw new Error('No voiceover duration found on the item. Run an NCA /v1/media/metadata node on the voiceover before this node.');
  }
  if (!amount || amount < 1) {
    throw new Error('Invalid "Image Amount": ' + j['Image Amount']);
  }

  // seconds each image is held — derived from the real voiceover length
  const perImage = (duration / amount).toFixed(6);

  // inputs[0] = voiceover, inputs[1..N] = looped images each held for perImage seconds
  const inputs = [{ file_url: voiceover }];
  for (let i = 1; i <= amount; i++) {
    inputs.push({
      file_url: `${imageBase}${i}${ext}`,
      options: [
        { option: '-loop', argument: '1' },
        { option: '-t',    argument: perImage },
      ],
    });
  }

  // normalize each image onto the same canvas (no distortion), then concat in order
  const norm = (n) =>
    `[${n}:v]scale=${WIDTH}:${HEIGHT}:force_original_aspect_ratio=decrease,` +
    `pad=${WIDTH}:${HEIGHT}:(ow-iw)/2:(oh-ih)/2,setsar=1,fps=${FPS},format=yuv420p[v${n}]`;

  const norms  = [];
  const labels = [];
  for (let i = 1; i <= amount; i++) { norms.push(norm(i)); labels.push(`[v${i}]`); }
  const filter = `${norms.join(';')};${labels.join('')}concat=n=${amount}:v=1:a=0[outv]`;

  const payload = {
    inputs,
    filters: [{ filter }],
    outputs: [{
      options: [
        { option: '-map',     argument: '[outv]' },
        { option: '-map',     argument: '0:a' },
        { option: '-c:v',     argument: 'libx264' },
        { option: '-preset',  argument: 'medium' },
        { option: '-crf',     argument: '23' },
        { option: '-pix_fmt', argument: 'yuv420p' },
        { option: '-c:a',     argument: 'aac' },
        { option: '-b:a',     argument: '192k' },
        { option: '-shortest' },
      ],
    }],
    metadata: { thumbnail: false, filesize: true, duration: true, bitrate: false, encoder: false },
    id: `slideshow_${idx}_${Date.now()}`,
  };
  if (WEBHOOK_URL) payload.webhook_url = WEBHOOK_URL;

  return { json: payload };
});
